1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	type Item = { type: string };
12	type QuoteStep = { op: "quote"; items: Item[] };
13	type Scenario = {
14	  customer: { yearsWithMHPCO: number };
15	  steps: QuoteStep[];
16	};
17	type QuoteResult = { premium: number };
18	
19	const itemPremium = (item: Item): number => {
20	  const base = BASE_PREMIUMS[item.type];
21	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE;
22	  return base + firstInsuranceSurcharge;
23	};
24	
25	const quotePremium = (step: QuoteStep): QuoteResult => {
26	  const itemsTotal = step.items.reduce((sum, item) => sum + itemPremium(item), 0);
27	  return { premium: Math.ceil(itemsTotal + PROCESSING_FEE) };
28	};
29	
30	export const run = (scenario: Scenario): { results: QuoteResult[] } => {
31	  return { results: scenario.steps.map(quotePremium) };
32	};
33

1	import { describe, it, expect } from "vitest";
2	import { run } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Simplest cases ---
6	  it("empty item list yields premium 5 G (only the processing fee)", () => {
7	    const result = run({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Single main items at base premium (newcomer, first contract scenario adds first-insurance surcharge per-item; use plain config: years=0, with no prior contract) ---
15	  // We start with simpler cases: a long-standing customer (≥2 yrs) on a follow-up contract — but the simplest is one main item alone.
16	  // Use single-item, plain (no curse, no high enchantment) to test base premiums in isolation; modifiers will be tested in dedicated cases below.
17	
18	  it("single sword (plain) for newcomer → 100 base + 10 first-insurance + 5 fee = 115 G", () => {
19	    const result = run({
20	      customer: { yearsWithMHPCO: 0 },
21	      steps: [
22	        {
23	          op: "quote",
24	          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
25	        },
26	      ],
27	    });
28	    expect(result).toEqual({ results: [{ premium: 115 }] });
29	  });
30	  it("single amulet (plain) for newcomer → 60 + 6 + 5 = 71 G", () => {
31	    const result = run({
32	      customer: { yearsWithMHPCO: 0 },
33	      steps: [
34	        {
35	          op: "quote",
36	          items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }],
37	        },
38	      ],
39	    });
40	    expect(result).toEqual({ results: [{ premium: 71 }] });
41	  });
42	  it("single staff (plain) for newcomer → 80 + 8 + 5 = 93 G", () => {
43	    const result = run({
44	      customer: { yearsWithMHPCO: 0 },
45	      steps: [
46	        {
47	          op: "quote",
48	          items: [{ type: "staff", material: "oak", enchantment: 2, cursed: false }],
49	        },
50	      ],
51	    });
52	    expect(result).toEqual({ results: [{ premium: 93 }] });
53	  });
54	  it("single potion (plain) for newcomer → 40 + 4 + 5 = 49 G", () => {
55	    const result = run({
56	      customer: { yearsWithMHPCO: 0 },
57	      steps: [
58	        {
59	          op: "quote",
60	          items: [{ type: "potion", material: "glass", enchantment: 1, cursed: false }],
61	        },
62	      ],
63	    });
64	    expect(result).toEqual({ results: [{ premium: 49 }] });
65	  });
