67	  // --- Components: per-unit and block discount ---
68	  it.todo("2 runes → 50 G base premium (no block)");
69	  it.todo("3 runes → 60 G base premium (block of 3 alike)");
70	  it.todo("4 runes → 100 G base premium (no block — needs exactly 3)");
71	  it.todo("7 runes → 175 G base premium (no blocks applied to leftover groupings beyond 3-alike rule per spec example)");
72	
73	  // --- "Alike" components clarification ---
74	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
75	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
76	
77	  // --- Modifier scope on multi-item policy ---
78	  it.todo("cursed sword + plain amulet → policy base 160 G; curse adds 50 G (on sword base) → 210 G before policy modifiers and fee");
79	
80	  // --- Modifier thresholds ---
81	  it.todo("customer with exactly 2 years → loyalty discount applies");
82	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
83	  it.todo("cursed sword with enchantment 5 → both surcharges apply");
84	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
85	
86	  // --- Insurance value sums & cap ---
87	  it.todo("policy covers sword + amulet → insurance sum 1600 G, cap 3200 G");
88	  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value)");
89	  it.todo("sword + 3 runes (block) → insurance sum 1750 G; block discount affects premium only, not insurance sum");
90	  it.todo("two swords → insurance sum 2000 G, cap 4000 G");
91	
92	  // --- Claims: standard reimbursement (no special clauses) ---
93	  it.todo("regular sword (steel, enchantment 3), damage 500 → payout 400 (500 − 100 deductible)");
94	  it.todo("rune (250 G), damage 200 → payout 100 (200 − 100 deductible; no enchantment/material on rune)");
95	
96	  // --- Claims: enchantment threshold ---
97	  it.todo("dragon-material sword, enchantment 8, damage 1000 → payout 400 (high-enchant 50% then deductible: 500 − 100)");
98	  it.todo("dragon-material sword, enchantment 9, damage 1000 → payout 400 (both clauses; 50% wins then deductible)");
99	  it.todo("dragon-material sword, enchantment 5, damage 800 → payout 700 (only dragon: full then deductible)");
100	  it.todo("steel sword, enchantment 9, damage 1000 → payout 400 (only high-enchant; 50% then deductible)");
101	
102	  // --- Deductible per damage event ---
103	  it.todo("dragon attack: sword damage 500 + amulet damage 300 → payout 600 (deductible per item: (500−100)+(300−100))");
104	
105	  // --- Multiple items of same type ---
106	  it.todo("two swords damaged → each treated as separate damage with its own deductible");
107	  it.todo("damages array has more entries of a type than policy covers → CLI exits non-zero");
108	
109	  // --- Cap exhaustion across successive claims ---
110	  it.todo("sword (cap 2000): first claim 1500 → payout 1400, remainingCap 600; second claim 1500 → payout 600, remainingCap 0");
111	
112	  // --- Rounding ---
113	  it.todo("premium calculation that yields 197.5 → final 198 (rounded up)");
114	  it.todo("payout calculation that yields 350.5 → final 350 (rounded down)");
115	
116	  // --- Edge cases / errors ---
117	  it.todo("quote with unknown item type (e.g. broomstick) → CLI exits non-zero with stderr message");
118	  it.todo("claim damages an item not in policy (e.g. amulet damaged when only sword insured) → CLI exits non-zero");
119	  it.todo("claim damages an item with unknown type → CLI exits non-zero");
120	  it.todo("claim with negative damage amount → CLI exits non-zero");
121	
122	  // --- Integration examples ---
123	  it.todo("newcomer with cursed steel sword (enchantment 3): 100 + 50 + 10 + 5 = 165 G");
124	  it.todo("3-year customer's second quote with cursed steel sword (enchantment 7): 100 + 50 + 30 − 20 + 10 − 15 + 5 = 160 G");
125	});
126	
